import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"心能卡","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/心能卡/心能卡.md","filePath":"4.资源分区/6.技艺及称号/杂项/心能卡/心能卡.md"}'),p={name:"4.资源分区/6.技艺及称号/杂项/心能卡/心能卡.md"};function d(l,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"心能卡",tabindex:"-1"},[s("心能卡 "),e("a",{class:"header-anchor",href:"#心能卡","aria-label":'Permalink to "心能卡"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),o('<h1 id="心能卡-1" tabindex="-1">心能卡 <a class="header-anchor" href="#心能卡-1" aria-label="Permalink to &quot;心能卡&quot;">​</a></h1><p>心能卡<br> 心能卡，即末世之战后出现的，能够收集并在主神空间中兑换的特殊物资，但收集这些心能卡需要先经过一些简单的训练，在接受训练之后，某些战斗或影片结束时，都有可能可以收集到心能卡。</p><p>D+500<br> 收集训练<br> 特殊的，如果此资源在环团中使用，则购买收集训练不占据任何评级，在心能卡兑换前，不计算任何评级。<br> 收集训练不会提供内在属性。</p><p>收集心能卡：在一场至少与你的内在支线同等级的战斗结束后，由ST投一次D2，1为出现心能卡，2为未出现。若出现心能卡，则可以收集之，由ST再投一次D2，决定是未知的心能卡或是已知的心能卡。若为未知的心能卡，则直接获得之，持有者可以在主神空间中进行鉴定，投一次DX=所有心能卡种类，根据出目按照顺序得知这张心能卡为什么具体牌张；若是已知的心能卡，则由ST进行这个流程。<br> 一场影片中，人物至多从中收集3张心能卡。</p><p>兑换心能卡：无论是否拥有收集训练，持有足够数目规定种类的心能卡的轮回者可在主神处消耗这些心能卡兑换其上记载的资源。在兑换后，若该资源会占据评级，正常计算之。</p><p>兑换示例：<br> 轮回者教皇持有5张【散塔成沙】，在主神处消耗它们以兑换【沙之书】，在兑换前，这些心能卡不占据任何评级，在兑换后，正常计算评级。</p><p>集换心能卡：<br> 心能卡可以用于交换，售卖，但仅限于轮回者之间，无法交给主神空间回收以获得分数。<br> 主神空间指导价格：每张某种类心能卡=500分。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
